 30	/*************************************************************************/
 31	/* PDU RX functions                                                      */
 32	/*************************************************************************/
 33	
 34	static int modulus_rx(rlc_entity_um_t *entity, int a)
 35	{
 36	  /* as per 36.322 7.1, modulus base is vr(uh)-window_size and modulus is
 37	   * 2^sn_field_length (which is 'sn_modulus' in rlc_entity_um_t)
 38	   */
 39	  int r = a - (entity->vr_uh - entity->window_size);
 40	  if (r < 0) r += entity->sn_modulus;
 41	  return r % entity->sn_modulus;
 42	}
 43	
 44	static int sn_compare_rx(void *_entity, int a, int b)
 45	{
 46	  rlc_entity_um_t *entity = _entity;
 47	  return modulus_rx(entity, a) - modulus_rx(entity, b);
 48	}
 49	
 50	static int sn_in_recv_window(void *_entity, int sn)
 51	{
 52	  rlc_entity_um_t *entity = _entity;
 53	  int mod_sn = modulus_rx(entity, sn);
 54	  /* we simplify (VR(UH) - UM_Window_Size) <= SN < VR(UH), base is
 55	   * (VR(UH) - UM_Window_Size) and VR(UH) = base + window_size
 56	   */
 57	  return mod_sn < entity->window_size;
 58	}
 59	
 60	/* return 1 if a PDU with SN == 'sn' is in the rx list, 0 otherwise */
 61	static int rlc_um_pdu_received(rlc_entity_um_t *entity, int sn)
 62	{
 63	  rlc_rx_pdu_segment_t *cur = entity->rx_list;
 64	  while (cur != NULL) {
 65	    if (cur->sn == sn)
 66	      return 1;
 67	    cur = cur->next;
 68	  }
 69	  return 0;
 70	}
 71	
 72	static int less_than_vr_ur(rlc_entity_um_t *entity, int sn)
 73	{
 74	  return sn_compare_rx(entity, sn, entity->vr_ur) < 0;
 75	}
 76	
 77	static int outside_of_reordering_window(rlc_entity_um_t *entity, int sn)
 78	{
 79	  return !sn_in_recv_window(entity, sn);
 80	}
 81	
 82	static int less_than_vr_uh(rlc_entity_um_t *entity, int sn)
 83	{
 84	  return sn_compare_rx(entity, sn, entity->vr_uh) < 0;
 85	}
 86	
 87	static void rlc_um_reassemble_pdu(rlc_entity_um_t *entity,
 88	    rlc_rx_pdu_segment_t *pdu)
 89	{
 90	  rlc_um_reassemble_t *r = &entity->reassemble;
 91	
 92	  int fi;
 93	  int e;
 94	  int sn;
 95	  int data_pos;
 96	  int sdu_len;
 97	  int sdu_offset;
 98	
 99	  sdu_offset = pdu->data_offset;
100	
101	  rlc_pdu_decoder_init(&r->dec, pdu->data, pdu->size);
102	
103	  if (entity->sn_field_length == 10)
104	    rlc_pdu_decoder_get_bits(&r->dec, 3);
105	
106	  fi = rlc_pdu_decoder_get_bits(&r->dec, 2);
107	  e  = rlc_pdu_decoder_get_bits(&r->dec, 1);
108	  sn = rlc_pdu_decoder_get_bits(&r->dec, entity->sn_field_length);
109	
110	  if (e) {
111	    e       = rlc_pdu_decoder_get_bits(&r->dec, 1);
112	    sdu_len = rlc_pdu_decoder_get_bits(&r->dec, 11);
113	  } else
114	    sdu_len = pdu->size - sdu_offset;
115	
116	  /* discard current SDU being reassembled if bad SN or bad FI */
117	  if (sn != (r->sn + 1) % entity->sn_modulus ||
118	      !(fi & 0x02)) {
119	    if (r->sdu_pos)
120	      LOG_D(RLC, "%s:%d:%s: warning: discard partially reassembled SDU\n",
121	            __FILE__, __LINE__, __FUNCTION__);
122	    r->sdu_pos = 0;
123	  }
124	
125	  /* if the head of the SDU is missing, still process the PDU
126	   * but remember to discard the reassembled SDU later on (the
127	   * head has not been received).
128	   * The head is missing if sdu_pos == 0 and fi says the PDU does not
129	   * start an SDU.
130	   */
131	  if (r->sdu_pos == 0 && (fi & 0x02))
132	    r->sdu_head_missing = 1;
133	
134	  r->sn = sn;
135	  data_pos = pdu->data_offset;
136	
137	  while (1) {
138	    if (r->sdu_pos >= SDU_MAX) {
139	      /* TODO: proper error handling (discard PDUs with current sn from
140	       * reassembly queue? something else?)
141	       */
142	      LOG_E(RLC, "%s:%d:%s: bad RLC PDU\n", __FILE__, __LINE__, __FUNCTION__);
143	      exit(1);
144	    }
145	    r->sdu[r->sdu_pos] = pdu->data[data_pos];
146	    r->sdu_pos++;
147	    data_pos++;
148	    if (data_pos == sdu_offset + sdu_len) {
149	      /* all bytes of SDU are consumed, check if SDU is fully there.
150	       * It is if the data pointer is not at the end of the PDU segment
151	       * or if 'fi' & 1 == 0
152	       */
153	      if (data_pos != pdu->size || (fi & 1) == 0) {
154	        /* time to discard the SDU if we didn't receive the head */
155	        if (r->sdu_head_missing) {
156	          LOG_D(RLC, "%s:%d:%s: warning: discard SDU, head not received\n",
157	                __FILE__, __LINE__, __FUNCTION__);
158	          r->sdu_head_missing = 0;
159	        } else {
160	          /* SDU is full - deliver to higher layer */
161	          entity->common.deliver_sdu(entity->common.deliver_sdu_data,
162	                                     (rlc_entity_t *)entity,
163	                                     r->sdu, r->sdu_pos);
164	        }
165	        r->sdu_pos = 0;
166	      }
167	      /* done with PDU? */
168	      if (data_pos == pdu->size)
169	        break;
170	      /* not at the end of PDU, process next SDU */
171	      sdu_offset += sdu_len;
172	      if (e) {
173	        e       = rlc_pdu_decoder_get_bits(&r->dec, 1);
174	        sdu_len = rlc_pdu_decoder_get_bits(&r->dec, 11);
175	      } else
176	        sdu_len = pdu->size - sdu_offset;
177	    }
178	  }
179	}
180	
181	static void rlc_um_reassemble(rlc_entity_um_t *entity,
182	    int (*check_sn)(rlc_entity_um_t *entity, int sn))
183	{
184	  rlc_rx_pdu_segment_t *cur;
185	
186	  /* process all PDUs from head of rx list until all is processed or
187	   * the SN is not valid anymore with respect to 'check_sn'
188	   */
189	  while (entity->rx_list != NULL && check_sn(entity, entity->rx_list->sn)) {
190	    cur = entity->rx_list;
191	    rlc_um_reassemble_pdu(entity, cur);
192	    entity->rx_size -= cur->size;
193	    entity->rx_list = cur->next;
194	    rlc_rx_free_pdu_segment(cur);
195	  }
196	}
